CREATE TYPE "MatchStatus" AS ENUM ('WAITING','ACTIVE','COMPLETED','ABANDONED');CREATE TYPE "MatchMode" AS ENUM ('CASUAL','RANKED');
CREATE TABLE "Match"("id" TEXT PRIMARY KEY,"mode" "MatchMode" NOT NULL DEFAULT 'CASUAL',"status" "MatchStatus" NOT NULL DEFAULT 'WAITING',"seed" TEXT NOT NULL,"winnerId" TEXT,"reason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"endedAt" TIMESTAMP(3));
CREATE TABLE "MatchPlayer"("matchId" TEXT NOT NULL REFERENCES "Match"("id") ON DELETE CASCADE,"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"deckId" TEXT NOT NULL,"seat" INTEGER NOT NULL,"connectedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"disconnectedAt" TIMESTAMP(3),PRIMARY KEY("matchId","userId"),UNIQUE("matchId","seat"));
CREATE TABLE "MatchAction"("id" TEXT PRIMARY KEY,"actionId" TEXT NOT NULL,"matchId" TEXT NOT NULL REFERENCES "Match"("id") ON DELETE CASCADE,"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"version" INTEGER NOT NULL,"payload" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("matchId","actionId"));CREATE INDEX "MatchAction_matchId_version_idx" ON "MatchAction"("matchId","version");
CREATE TABLE "RankedSeason"("id" TEXT PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"startsAt" TIMESTAMP(3) NOT NULL,"endsAt" TIMESTAMP(3) NOT NULL,"active" BOOLEAN NOT NULL DEFAULT false);
CREATE TABLE "UserRank"("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"seasonId" TEXT NOT NULL REFERENCES "RankedSeason"("id") ON DELETE CASCADE,"rating" INTEGER NOT NULL DEFAULT 1000,"tier" TEXT NOT NULL DEFAULT 'BRONZE',"wins" INTEGER NOT NULL DEFAULT 0,"losses" INTEGER NOT NULL DEFAULT 0,"rewardClaimed" BOOLEAN NOT NULL DEFAULT false,PRIMARY KEY("userId","seasonId"));CREATE INDEX "UserRank_seasonId_rating_idx" ON "UserRank"("seasonId","rating");
CREATE TABLE "GameEvent"("id" TEXT PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"description" TEXT NOT NULL,"startsAt" TIMESTAMP(3) NOT NULL,"endsAt" TIMESTAMP(3) NOT NULL,"currencyCode" TEXT NOT NULL,"stages" JSONB NOT NULL);
CREATE TABLE "EventShopItem"("id" TEXT PRIMARY KEY,"eventId" TEXT NOT NULL REFERENCES "GameEvent"("id") ON DELETE CASCADE,"cardId" TEXT,"name" TEXT NOT NULL,"cost" INTEGER NOT NULL,"stock" INTEGER,"cosmetic" BOOLEAN NOT NULL DEFAULT false,"metadata" JSONB);CREATE INDEX "EventShopItem_eventId_idx" ON "EventShopItem"("eventId");
CREATE TABLE "UserEventCurrency"("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"eventId" TEXT NOT NULL REFERENCES "GameEvent"("id") ON DELETE CASCADE,"balance" INTEGER NOT NULL DEFAULT 0,PRIMARY KEY("userId","eventId"));
